// Space: O(1)

// greedy
class Solution {
public:
    int removeAlmostEqualCharacters(string word) {
        int result = 0;
        for (int i = 0; (i + 1) + result < size(word); ++i) {
            if (abs(word[(i + 1) + result] - word[i + result]) <= 1) {
                ++result;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# greedy
class Solution(object):
    def removeAlmostEqualCharacters(self, word):
        """
        :type word: str
        :rtype: int
        """
        result = 0
        for i in xrange(len(word)-1):
            if (i+1)+result >= len(word):
                break
            if abs(ord(word[(i+1)+result])-ord(word[i+result])) <= 1:
                result += 1
        return result
